import{_ as t,o as l,c as e,a2 as i}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"✨ 功能特性","description":"","frontmatter":{},"headers":[],"relativePath":"features.md","filePath":"features.md","lastUpdated":1783855136000}'),r={name:"features.md"};function d(h,a,o,n,s,u){return l(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="✨-功能特性" tabindex="-1">✨ 功能特性 <a class="header-anchor" href="#✨-功能特性" aria-label="Permalink to &quot;✨ 功能特性&quot;">​</a></h1><p>AgoraIn 提供全面的课堂签到管理功能，以下是所有支持的特性详解。</p><hr><h2 id="签到操作" tabindex="-1">签到操作 <a class="header-anchor" href="#签到操作" aria-label="Permalink to &quot;签到操作&quot;">​</a></h2><h3 id="✅-一键打卡" tabindex="-1">✅ 一键打卡 <a class="header-anchor" href="#✅-一键打卡" aria-label="Permalink to &quot;✅ 一键打卡&quot;">​</a></h3><p>教师在大屏客户端上点击学生姓名，瞬时完成签到。操作简单直观，适合课堂场景快速响应。</p><ul><li><strong>左键点击</strong>：完成签到</li><li>签到时间精确记录</li><li>支持连续快速点击多名学生</li></ul><h3 id="↩-即时取消" tabindex="-1">↩ 即时取消 <a class="header-anchor" href="#↩-即时取消" aria-label="Permalink to &quot;↩ 即时取消&quot;">​</a></h3><p>签到误操作时可以立即撤销：</p><ul><li><strong>右键点击</strong>已签到学生即可取消</li><li>不影响其他学生的签到记录</li><li>取消后可重新签到</li></ul><hr><h2 id="数据统计" tabindex="-1">数据统计 <a class="header-anchor" href="#数据统计" aria-label="Permalink to &quot;数据统计&quot;">​</a></h2><h3 id="📊-实时仪表盘" tabindex="-1">📊 实时仪表盘 <a class="header-anchor" href="#📊-实时仪表盘" aria-label="Permalink to &quot;📊 实时仪表盘&quot;">​</a></h3><p>客户端实时展示签到统计数据：</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>签到人数</td><td>已签到学生数 / 总人数</td></tr><tr><td>出勤率</td><td>百分比显示，直观明了</td></tr><tr><td>最早签到</td><td>第一个完成签到的学生和时间</td></tr><tr><td>最晚签到</td><td>最后一个完成签到的学生和时间</td></tr></tbody></table><h3 id="🏆-排行榜" tabindex="-1">🏆 排行榜 <a class="header-anchor" href="#🏆-排行榜" aria-label="Permalink to &quot;🏆 排行榜&quot;">​</a></h3><p>实时显示最早签到的 <strong>前 3 名</strong> 学生：</p><ul><li>🥇 <strong>金牌</strong> — 第一名</li><li>🥈 <strong>银牌</strong> — 第二名</li><li>🥉 <strong>铜牌</strong> — 第三名</li><li>排行榜实时更新，激励学生快速签到</li></ul><hr><h2 id="多任务管理-v2-7-新功能" tabindex="-1">多任务管理 （v2.7 新功能） <a class="header-anchor" href="#多任务管理-v2-7-新功能" aria-label="Permalink to &quot;多任务管理 （v2.7 新功能）&quot;">​</a></h2><h3 id="📋-独立任务管理" tabindex="-1">📋 独立任务管理 <a class="header-anchor" href="#📋-独立任务管理" aria-label="Permalink to &quot;📋 独立任务管理&quot;">​</a></h3><ul><li>支持同时创建多个打卡任务</li><li>每个任务独立管理学生名单</li><li><strong>标签页切换</strong>在不同任务之间快速跳转</li></ul><h3 id="🔄-后台同步" tabindex="-1">🔄 后台同步 <a class="header-anchor" href="#🔄-后台同步" aria-label="Permalink to &quot;🔄 后台同步&quot;">​</a></h3><ul><li>未打开的标签页自动在后台连接服务器</li><li>数据实时同步，不会遗漏任何签到</li><li>切换标签页时数据即时更新</li></ul><hr><h2 id="远程签到" tabindex="-1">远程签到 <a class="header-anchor" href="#远程签到" aria-label="Permalink to &quot;远程签到&quot;">​</a></h2><h3 id="📱-短链接签到" tabindex="-1">📱 短链接签到 <a class="header-anchor" href="#📱-短链接签到" aria-label="Permalink to &quot;📱 短链接签到&quot;">​</a></h3><ol><li>教师在 Web 管理面板创建签到任务</li><li>系统自动生成短链接</li><li>教师分享链接给学生</li><li>学生点击链接即可完成签到</li></ol><h3 id="📷-二维码签到" tabindex="-1">📷 二维码签到 <a class="header-anchor" href="#📷-二维码签到" aria-label="Permalink to &quot;📷 二维码签到&quot;">​</a></h3><ul><li>客户端自动生成签到二维码</li><li>学生使用手机扫码完成签到</li><li>无需安装任何 App</li><li>基于 QRCoder 库生成</li></ul><hr><h2 id="web-管理面板" tabindex="-1">Web 管理面板 <a class="header-anchor" href="#web-管理面板" aria-label="Permalink to &quot;Web 管理面板&quot;">​</a></h2><h3 id="🌐-浏览器管理" tabindex="-1">🌐 浏览器管理 <a class="header-anchor" href="#🌐-浏览器管理" aria-label="Permalink to &quot;🌐 浏览器管理&quot;">​</a></h3><p>不需要安装客户端，通过浏览器即可：</p><ul><li>查看所有签到记录</li><li>创建和管理签到任务</li><li>设备分组管理</li><li>数据导出操作</li></ul><h3 id="📁-设备分组" tabindex="-1">📁 设备分组 <a class="header-anchor" href="#📁-设备分组" aria-label="Permalink to &quot;📁 设备分组&quot;">​</a></h3><p>服务器按照设备 UUID 自动分组：</p><ul><li>每个客户端设备独立管理</li><li>一目了然的设备状态</li><li>便于多班级同时使用</li></ul><hr><h2 id="数据管理" tabindex="-1">数据管理 <a class="header-anchor" href="#数据管理" aria-label="Permalink to &quot;数据管理&quot;">​</a></h2><h3 id="📤-csv-导出" tabindex="-1">📤 CSV 导出 <a class="header-anchor" href="#📤-csv-导出" aria-label="Permalink to &quot;📤 CSV 导出&quot;">​</a></h3><ul><li>一键导出签到数据为 CSV 格式</li><li>兼容 Microsoft Excel 和 WPS</li><li>数据包含：学生姓名、签到时间、设备信息</li></ul><h3 id="📥-csv-导入" tabindex="-1">📥 CSV 导入 <a class="header-anchor" href="#📥-csv-导入" aria-label="Permalink to &quot;📥 CSV 导入&quot;">​</a></h3><ul><li>从 CSV 文件批量导入学生名单</li><li>快速切换班级或课程</li><li>减少手动输入工作</li></ul><h3 id="🗑-一键清空" tabindex="-1">🗑 一键清空 <a class="header-anchor" href="#🗑-一键清空" aria-label="Permalink to &quot;🗑 一键清空&quot;">​</a></h3><ul><li>管理员三次确认后安全清空所有记录</li><li>防止误操作丢失数据</li><li>建议清空前先导出备份</li></ul><hr><h2 id="安全机制" tabindex="-1">安全机制 <a class="header-anchor" href="#安全机制" aria-label="Permalink to &quot;安全机制&quot;">​</a></h2><h3 id="🔐-rsa-加密通信" tabindex="-1">🔐 RSA 加密通信 <a class="header-anchor" href="#🔐-rsa-加密通信" aria-label="Permalink to &quot;🔐 RSA 加密通信&quot;">​</a></h3><p>客户端与服务器之间的通信安全由 RSA-2048 + SHA256 保证：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>客户端 ──RSA 签名请求──▶ 服务器</span></span>
<span class="line"><span>客户端 ◀──RSA 验证响应── 服务器</span></span></code></pre></div><h3 id="🛡-hmac-sha256" tabindex="-1">🛡 HMAC-SHA256 <a class="header-anchor" href="#🛡-hmac-sha256" aria-label="Permalink to &quot;🛡 HMAC-SHA256&quot;">​</a></h3><ul><li>数据完整性校验</li><li>防止中间人篡改</li><li>请求签名验证</li></ul><hr><h2 id="技术架构一览" tabindex="-1">技术架构一览 <a class="header-anchor" href="#技术架构一览" aria-label="Permalink to &quot;技术架构一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>技术</th><th>版本</th></tr></thead><tbody><tr><td>桌面客户端</td><td>WPF (.NET)</td><td>.NET 10.0</td></tr><tr><td>服务器</td><td>ASP.NET Core Minimal API</td><td>.NET 10.0</td></tr><tr><td>数据库</td><td>SQLite (EF Core)</td><td>—</td></tr><tr><td>通信安全</td><td>RSA-2048 + HMAC-SHA256</td><td>—</td></tr><tr><td>二维码</td><td>QRCoder</td><td>1.6.0</td></tr><tr><td>架构模式</td><td>MVVM</td><td>—</td></tr><tr><td>数据格式</td><td>JSON / CSV</td><td>—</td></tr><tr><td>跨平台</td><td>Kestrel Web Server</td><td>—</td></tr></tbody></table>`,56)])])}const q=t(r,[["render",d]]);export{b as __pageData,q as default};
